"""Unit tests for the Book class."""import pytestfrom src.models.book import Bookclass TestBook:    """Test suite for Book class."""    @pytest.fixture    def sample_book(self):        """Create a sample book for testing."""        return Book(            title="Clean Code",            author="Robert C. Martin",            isbn="978-0132350884",            publication_year=2008        )    def test_book_initialization(self, sample_book):        """Test that a new book is available."""        assert sample_book.title == "Clean Code"        assert sample_book.is_available() is True        assert sample_book.is_reference is False    def test_check_out_success(self, sample_book):        """Test successful checkout."""        result = sample_book.check_out()        assert result is True        assert sample_book.is_available() is False    def test_check_out_fails_when_already_checked_out(self, sample_book):        """Test that checking out an unavailable book returns False."""        sample_book.check_out()        result = sample_book.check_out()        assert result is False    def test_check_in_success(self, sample_book):        """Test successful return."""        sample_book.check_out()        result = sample_book.check_in()        assert result is True        assert sample_book.is_available() is True    def test_check_in_fails_when_not_checked_out(self, sample_book):        """Test that returning an available book returns False."""        result = sample_book.check_in()        assert result is False    def test_reference_book_can_still_be_checked_out(self):        """Reference books can be checked out (but will have shorter loan period handled elsewhere)."""        ref_book = Book("Encyclopedia", "Various", "123", 2020, is_reference=True)        assert ref_book.check_out() is True